class Solution:
    def maxProduct(self, words: List[str]) -> int:
        masks, lens = [], []
        for w in words:
            m = 0
            for c in w:
                m |= 1 << (ord(c)-97)
            masks.append(m); lens.append(len(w))
        ans = 0
        for i in range(len(words)):
            for j in range(i+1, len(words)):
                if masks[i] & masks[j] == 0:
                    ans = max(ans, lens[i]*lens[j])
        return ans

