class Solution {
public:
    int maxProduct(vector<string>& words) {
        vector<int> mask, len;
        for (auto& w : words) {
            int m = 0;
            for (char c : w) m |= 1 << (c-'a');
            mask.push_back(m); len.push_back(w.size());
        }
        int ans = 0;
        for (int i = 0; i < (int)words.size(); i++)
            for (int j = i+1; j < (int)words.size(); j++)
                if ((mask[i] & mask[j]) == 0)
                    ans = max(ans, len[i]*len[j]);
        return ans;
    }
};

