int maxProduct(char** words, int n) {
    int* mask = malloc(n*sizeof(int)); int* len = malloc(n*sizeof(int));
    for (int i=0;i<n;i++){
        mask[i]=0; len[i]=strlen(words[i]);
        for (char* p=words[i];*p;p++) mask[i]|=1<<(*p-'a');
    }
    int ans=0;
    for (int i=0;i<n;i++) for (int j=i+1;j<n;j++)
        if ((mask[i]&mask[j])==0) { int v=len[i]*len[j]; if (v>ans) ans=v; }
    free(mask); free(len); return ans;
}
